{
    "model": "gpt-5",
    "instructions": "Tugasmu mengekstrak data transaksi keuangan dari input user. Jika input BUKAN transaksi keuangan (tidak ada intent pemasukan/pengeluaran atau nominal transaksi), set error=true dan isi error_cause. Dalam kondisi error, isi field lain dengan nilai default aman: type='expense', description='', amount=0, currency='IDR', category='unknown', account=null. Selalu output JSON valid sesuai schema, tanpa teks tambahan.",
    "input": "nama saya batman",
    "text": {
        "format": {
            "type": "json_schema",
            "name": "financial_transaction",
            "schema": {
                "type": "object",
                "properties": {
                    "error":{
                        "type": "boolean"
                    },
                    "error_cause":{
                        "type": ["string", "null"]
                    },
                    "type": {
                        "type": "string",
                        "enum": [
                            "expense",
                            "income"
                        ]
                    },
                    "description": {
                        "type": "string"
                    },
                    "amount": {
                        "type": "number"
                    },
                    "currency": {
                        "type": "string"
                    },
                    "category": {
                        "type": "string"
                    },
                    "account": {
                        "type": ["string", "null"]
                    }
                },
                "required": [
                    "error",
                    "error_cause",
                    "type",
                    "description",
                    "amount",
                    "currency",
                    "category",
                    "account"
                ],
                "additionalProperties": false
            }
        }
    }
}
